package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

public class CSVFormatTest {

    private void setFinalField(Object target, String fieldName, Object value) throws Exception {
        Field field = CSVFormat.class.getDeclaredField(fieldName);
        field.setAccessible(true);

        // Remove final modifier from the field (Java 12+ may not allow this, but assuming Java 8 here)
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~Modifier.FINAL);

        field.set(target, value);
    }

    @Test
    public void testIsQuoteCharacterSet_whenQuoteCharacterIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set quoteCharacter to null
        setFinalField(format, "quoteCharacter", null);

        boolean result = format.isQuoteCharacterSet();
        assertFalse(result, "Expected isQuoteCharacterSet() to return false when quoteCharacter is null");
    }

    @Test
    public void testIsQuoteCharacterSet_whenQuoteCharacterIsNotNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Use reflection to set quoteCharacter to a non-null Character
        setFinalField(format, "quoteCharacter", Character.valueOf('"'));

        boolean result = format.isQuoteCharacterSet();
        assertTrue(result, "Expected isQuoteCharacterSet() to return true when quoteCharacter is not null");
    }
}
